import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.DoJCRnHG.js";const f=JSON.parse('{"title":"Sync Pipeline","description":"How the repository fans out one Markdown tree into three framework roots.","frontmatter":{"title":"Sync Pipeline","description":"How the repository fans out one Markdown tree into three framework roots."},"headers":[],"relativePath":"architecture/sync-pipeline.md","filePath":"architecture/sync-pipeline.md","lastUpdated":null}'),r={name:"architecture/sync-pipeline.md"};function n(l,e,s,c,d,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="sync-pipeline" tabindex="-1">Sync Pipeline <a class="header-anchor" href="#sync-pipeline" aria-label="Permalink to &quot;Sync Pipeline&quot;">​</a></h1><p>The custom pipeline is intentionally thin:</p><ol><li>load shared repository metadata</li><li>clear generated content from each framework root</li><li>copy <code>content/</code> into VitePress, Starlight, and Quartz</li><li>build each framework with its own base path</li><li>assemble the outputs into <code>dist/</code></li></ol><h2 id="why-copy-instead-of-share-directly" tabindex="-1">Why Copy Instead Of Share Directly <a class="header-anchor" href="#why-copy-instead-of-share-directly" aria-label="Permalink to &quot;Why Copy Instead Of Share Directly&quot;">​</a></h2><p>Each generator is simpler and more reliable when it can use its expected directory layout. A small sync step is cheaper than fighting framework assumptions in three different ways.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../concepts/content-model">Content Model</a></li><li><a href="./../workflows/authoring-flow">Authoring Flow</a></li><li><a href="./../reference/tooling-notes">Tooling Notes</a></li></ul>',7)])])}const y=t(r,[["render",n]]);export{f as __pageData,y as default};
